import (
	"sort"
)

func solve(nums []int64, queries [][]int64) []int64 {
	N := len(nums)

	// Preprocessing: Prefix sums of even numbers count
	// P[i] stores the count of even numbers in nums[0...i-1]
	P := make([]int64, N+1)
	for i := 0; i < N; i++ {
		P[i+1] = P[i]
		if nums[i]%2 == 0 {
			P[i+1]++
		}
	}

	results := make([]int64, len(queries))

	for qIdx, query := range queries {
		l := int(query[0])
		r := int(query[1])
		k := query[2]

		// countRemoved(X): count of even numbers in nums[l..r] that are <= X
		countRemoved := func(X int64) int64 {
			if X < 2 {
				return 0
			}

			// Find the index jPrime of the first element in nums[0..r] strictly greater than X.
			// We search in the range [0, r+1).
			jPrime := sort.Search(r+1, func(i int) bool {
				return nums[i] > X
			})

			// jMax is the index of the rightmost element <= X within [0, r].
			jMax := jPrime - 1

			// If jMax is before the start of our subarray l, no elements are removed.
			if jMax < l {
				return 0
			}

			// Count of even numbers in nums[l..jMax] = P[jMax + 1] - P[l]
			return P[jMax+1] - P[l]
		}

		// check(X): returns true if the number of remaining even numbers <= X is at least k
		check := func(X int64) bool {
			if X < 2 {
				return false
			}

			// Total count of positive even numbers <= X is floor(X/2)
			totalEvens := X / 2

			removedCount := countRemoved(X)

			remainingCount := totalEvens - removedCount

			return remainingCount >= k
		}

		// Binary Search for the smallest X such that check(X) is true.
		L := int64(1)
		// Safe upper bound: max k is 10^9. If no removal, answer is 2*10^9. Use 4*10^9 + margin.
		R := int64(4e9 + 100)

		ans := R

		for L <= R {
			Mid := L + (R-L)/2

			if check(Mid) {
				ans = Mid
				R = Mid - 1 // Try smaller X
			} else {
				L = Mid + 1 // Need larger X
			}
		}

		results[qIdx] = ans
	}

	return results
}

