package main

import (
	"sort"
)

func solve(nums []int64, queries [][]int64) []int64 {
	N := len(nums)

	// 1. Preprocessing: Prefix sums of even numbers
	// P[i] stores the count of even numbers in nums[0...i]
	P := make([]int64, N)
	if N > 0 {
		P[0] = 0
		if nums[0]%2 == 0 {
			P[0] = 1
		}
		for i := 1; i < N; i++ {
			P[i] = P[i-1]
			if nums[i]%2 == 0 {
				P[i]++
			}
		}
	}

	// Helper function to get R(X): count of even numbers in nums[l..r] that are <= X
	// l and r are 0-indexed.
	getRemovedEvenCount := func(l, r int, X int64) int64 {
		if l > r {
			return 0
		}

		// Find the index of the last element <= X in the whole array nums
		// sort.Search returns the smallest index i such that nums[i] > X.
		// We want index i-1.
		i_ub := sort.Search(N, func(i int) bool {
			return nums[i] > X
		})

		// r_prime is the effective upper bound index considering X and the query range r
		r_prime := i_ub - 1

		// The actual effective range is [l, r_prime] capped by [l, r]
		actual_r := min(r, r_prime)

		if actual_r < l {
			return 0
		}

		// Count of even numbers in nums[l ... actual_r]
		count_up_to_r := P[actual_r]

		count_up_to_l_minus_1 := int64(0)
		if l > 0 {
			count_up_to_l_minus_1 = P[l-1]
		}

		return count_up_to_r - count_up_to_l_minus_1
	}

	results := make([]int64, len(queries))

	// 2. Query Processing
	for i, query := range queries {
		l, r, k := int(query[0]), int(query[1]), query[2]

		// Binary Search for J = X/2. We search for the smallest J such that f(2J) >= k.
		// Lower bound: k (if nothing is removed, the k-th element is 2k)
		L := k
		// Upper bound: k + N (since at most N elements are removed)
		R := k + int64(N) + 1 

		ansJ := R

		for L <= R {
			J := L + (R-L)/2
			X := 2 * J

			// R(X): Count of removed even numbers <= X in nums[l..r]
			R_X := getRemovedEvenCount(l, r, X)

			// T(X) = J (Total even numbers <= X)
			// f(X) = T(X) - R(X) (Remaining even numbers <= X)
			f_X := J - R_X

			if f_X >= k {
				// J might be the answer, try smaller J
				ansJ = J
				R = J - 1
			} else {
				// J is too small, need larger J
				L = J + 1
			}
		}

		results[i] = 2 * ansJ
	}

	return results
}

func min(a, b int) int {
	if a < b {
		return a
	}
	return b
}
