import (
	"sort"
)

// solve solves the described problem.
func solve(nums []int64, queries [][]int64) []int64 {
	N := len(nums)

	// 1. Preprocessing: Calculate Prefix Sum P
	// P[i] stores the count of even numbers in nums[0...i-1]
	P := make([]int64, N+1)
	for i := 0; i < N; i++ {
		P[i+1] = P[i]
		if nums[i]%2 == 0 {
			P[i+1]++
		}
	}

	// Helper function to count even numbers in nums[l..r] that are <= X (C(X))
	// This function requires O(log N) time.
	countLE := func(X int64, l, r int) int64 {
		if X < 2 {
			return 0
		}

		// Find the index of the first element strictly greater than X (idx_gt)
		// Search range is [0, N)
		idx_gt := sort.Search(N, func(i int) bool {
			return nums[i] > X
		})

		// j_max is the index of the last element <= X
		j_max := idx_gt - 1

		// Determine the effective upper bound for counting
		r_eff := r
		if j_max < r {
			r_eff = j_max
		}

		// If the effective range is invalid or outside the query range
		if l > r_eff {
			return 0
		}

		// Count of evens in nums[l...r_eff] is P[r_eff + 1] - P[l]
		return P[r_eff+1] - P[l]
	}

	results := make([]int64, len(queries))

	// 2. Process queries
	for i, query := range queries {
		l := int(query[0])
		r := int(query[1])
		k := query[2]

		// Binary Search for the smallest multiplier m such that m - C(2m) >= k
		// We seek X = 2m.

		// Search range for m. Lower bound is 1 (for X=2).
		// Upper bound: k + N is sufficient, but 3*10^9 is extremely safe given k <= 10^9 and N <= 10^5.
		L := int64(1)
		R := int64(3000000000) // 3 * 10^9
		ansM := R

		for L <= R {
			M := L + (R-L)/2
			X := 2 * M

			// C_M is the count of removed evens <= X
			C_M := countLE(X, l, r)

			// Check if the rank of X (M - C_M) is at least k
			if M-C_M >= k {
				ansM = M
				R = M - 1 // Try to find a smaller m
			} else {
				L = M + 1 // Need a larger m
			}
		}

		// The result is X = 2 * ansM
		results[i] = 2 * ansM
	}

	return results
}
